            if (--in_degree[v] == 0) {
                q.push(v);
            }
        }
    }

    // 输出最大权值
    ll ans = 0;
    for (int i = 1; i <= scc_cnt; ++i) {
        ans = max(ans, dp[i]);
    }
    cout << ans << endl;

    return 0;
}
