/* 文件头注释：使用并查集维护图的连通性，动态处理顶点被雪覆盖的情况 */
#include <bits/stdc++.h>
using namespace std;

const int MAXN = 2e5 + 5;

int parent[MAXN];
bool covered[MAXN]; // 记录顶点是否被雪覆盖

// 并查集的查找操作，带路径压缩
int find(int u) {
    if (parent[u] != u) {
        parent[u] = find(parent[u]);
    }
    return parent[u];
}

// 并查集的合并操作
void unite(int u, int v) {
    int pu = find(u);
    int pv = find(v);
    if (pu != pv) {
        parent[pu] = pv;
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N, M;
    cin >> N >> M;

    // 初始化并查集
    for (int i = 1; i <= N; ++i) {
        parent[i] = i;
    }

    // 读取边并合并顶点
    for (int i = 0; i < M; ++i) {
        int u, v;
        cin >> u >> v;
        unite(u, v);
    }

    int Q;
    cin >> Q;

    while (Q--) {
        int type, u, v;
        cin >> type;
        if (type == 1) {
            cin >> u;
            covered[u] = true; // 标记顶点u被雪覆盖
        } else {
            cin >> u >> v;
            // 检查u和v是否在同一个连通分量中，并且都没有被雪覆盖
            if (find(u) == find(v) && !covered[u] && !covered[v]) {
                cout << "Yes\n";
            } else {
                cout << "No\n";
            }
        }
    }

    return 0;
}
